// Bind both runs' EventResults views and ok-bits to short, distinct names so
// z3 sees two concrete ghost terms it can hang triggers on.
let er1 = (r1.1)@;
let er2 = (r2.1)@;
let ok1 = r1.0;
let ok2 = r2.0;

// Peel apart `next_ensures` for each run into individual `==>` facts. Because
// `HostState::next_ensures` is an `open spec fn`, Verus unfolds it and each
// implication below is just (full body) ==> (one conjunct), which is trivially
// verifiable. Stating them as separate asserts forces z3 to register each
// conjunct as a stand-alone fact about the named ghost terms `er1`/`er2`/etc.,
// rather than having to re-penetrate a structurally identical
// `next_ensures(...)` application from two different sides.
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 == post1_netc.ok())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 == post2_netc.ok())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> er1.well_typed_events()
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> er2.well_typed_events()
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 ==> er1.event_seq() == er1.ios)
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 ==> er2.event_seq() == er2.ios)
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> ((ok1 || er1.sends.len() > 0)
                ==> post1_netc.history() == pre_netc.history() + er1.event_seq())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> ((ok2 || er2.sends.len() > 0)
                ==> post2_netc.history() == pre_netc.history() + er2.event_seq())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 ==> HostState::next(pre_self_.view(), post1_self_.view(), er1.ios))
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 ==> HostState::next(pre_self_.view(), post2_self_.view(), er2.ios))
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 ==> post1_self_.invariants(&post1_netc.my_end_point()))
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 ==> post2_self_.invariants(&post2_netc.my_end_point()))
);

// Trigger-aligning instantiations of the three per-index quantifiers inside
// `well_typed_events`, separately for each run. `well_typed_events` is
// `open spec`, so Verus unfolds the definition for free and the empty `by {}`
// body suffices. Re-stating each forall with an explicit `#[trigger]` on the
// indexed expression gives z3 matching trigger patterns for both `er1` and
// `er2`, closing the two-forall instantiation gap that left the file-level
// query at `unknown`.
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.sends.len()
    implies #[trigger] er1.sends[i] is Send by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.sends.len()
    implies #[trigger] er2.sends[i] is Send by {};
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.recvs.len()
    implies #[trigger] er1.recvs[i] is Receive by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.recvs.len()
    implies #[trigger] er2.recvs[i] is Receive by {};
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.clocks.len()
    implies (#[trigger] er1.clocks[i] is ReadClock) || (er1.clocks[i] is TimeoutReceive) by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.clocks.len()
    implies (#[trigger] er2.clocks[i] is ReadClock) || (er2.clocks[i] is TimeoutReceive) by {};

// Also align triggers for the `clocks.len() <= 1` conjunct so both runs are
// visible to z3 as bounded sequences.
assert(er1.well_typed_events() ==> er1.clocks.len() <= 1);
assert(er2.well_typed_events() ==> er2.clocks.len() <= 1);
